const body = $input.first().json.body || $input.first().json;

let contentType       = body.content_type || 'text';
let mediaUrl          = body.media_url    || null;
let transcriptionText = body.transcription_text || body.transcriptionText || null;
let contentText       = body.content_text || body.message_text || '';
let fileName          = body.file_name    || null;
let mediaDuration     = body.media_duration_sec || null;

// Raw Z-API field fallbacks
if (!mediaUrl) {
  if (body.audio?.audioUrl) {
    contentType   = 'audio';
    mediaUrl      = body.audio.audioUrl;
    mediaDuration = body.audio.seconds || null;
    transcriptionText = body.audio.transcription || body.audio.transcriptionText || null;
  } else if (body.video?.videoUrl) {
    contentType = 'video';
    mediaUrl    = body.video.videoUrl;
    contentText = body.video.caption || contentText;
  } else if (body.document?.documentUrl) {
    contentType = 'document';
    mediaUrl    = body.document.documentUrl;
    fileName    = body.document.fileName || body.document.title || null;
    contentText = body.document.caption || contentText;
  } else if (body.image?.imageUrl) {
    contentType = 'image';
    mediaUrl    = body.image.imageUrl;
    contentText = body.image.caption || contentText;
  }
}

return [{ json: {
  tenant_id:          body.tenant_id       || '5518085b-42e9-4608-8c56-890cef45ba9b',
  customer_id:        body.customer_id,
  conversation_id:    body.conversation_id,
  channel_id:         body.channel_id      || '58c4062a-9fe9-4ae2-abff-5a8b5236a79e',
  content_text:       contentText,
  content_type:       contentType,
  media_url:          mediaUrl,
  transcription_text: transcriptionText,
  file_name:          fileName,
  media_duration_sec: mediaDuration,
  customer_name:      body.customer_name   || 'Cliente',
  customer_phone:     body.customer_phone  || body.phone || '',
}}];

const payload    = $('Enriquecer Payload').first().json;
const messages   = $('Buscar Histórico').all().map(i => i.json);
const agentCfg   = $('Buscar Config IA').first().json || {};
const restrictToConfigured = agentCfg.restrict_to_configured_services === true;
const companyContext  = $('Buscar Contexto Empresa').first().json?.ai_context_text || '';
const businessProfile = $('Buscar Perfil Empresa').first().json?.profile_text || '';

// Try to get Whisper transcription if audio path ran
let transcriptionText = payload.transcription_text || null;
try {
  const tItems = $('Aplicar Transcrição').all();
  if (tItems.length > 0) transcriptionText = tItems[0].json?.transcription_text || transcriptionText;
} catch (e) {}

// Try to get GPT-4o image description if image path ran
let imageDescription = null;
try {
  const imgItems = $('Aplicar Descrição').all();
  if (imgItems.length > 0) imageDescription = imgItems[0].json?.image_description || null;
} catch (e) {}

// Build conversation history, labelling media messages
const history = messages.slice(-15).map(m => {
  const role = m.direction === 'inbound' ? 'Cliente' : 'Sofia';
  let text = m.content_text || '';
  if (!text) {
    if (m.content_type === 'audio')    text = '[Mensagem de voz]';
    else if (m.content_type === 'video')    text = '[Vídeo]';
    else if (m.content_type === 'document') text = '[Documento]';
    else if (m.content_type === 'image')    text = '[Imagem]';
  }
  return `${role}: ${text}`;
}).join('\n');

// Build user message based on content type
const contentType = payload.content_type || 'text';
let userMessage   = payload.content_text || '';

if (contentType === 'audio') {
  if (transcriptionText) {
    userMessage = `[Mensagem de voz transcrita]: ${transcriptionText}`;
  } else {
    const dur = payload.media_duration_sec ? ` de ${payload.media_duration_sec}s` : '';
    userMessage = `[O cliente enviou uma mensagem de voz${dur}. Não foi possível transcrever. Peça gentilmente para repetir por texto.]`;
  }
} else if (contentType === 'image') {
  if (imageDescription) {
    const caption = payload.content_text ? `\nLegenda do cliente: "${payload.content_text}"` : '';
    userMessage = `[O cliente enviou uma imagem]\nDescrição da imagem: ${imageDescription}${caption}`;
  } else {
    userMessage = payload.content_text
      ? `[O cliente enviou uma imagem com legenda]: ${payload.content_text}`
      : '[O cliente enviou uma imagem. Pergunte como pode ajudá-lo.]';
  }
} else if (contentType === 'video') {
  userMessage = payload.content_text
    ? `[O cliente enviou um vídeo com legenda]: ${payload.content_text}`
    : '[O cliente enviou um vídeo. Responda naturalmente e pergunte como pode ajudá-lo.]';
} else if (contentType === 'document') {
  const fname = payload.file_name ? ` "${payload.file_name}"` : '';
  userMessage = payload.content_text
    ? `[O cliente enviou um documento${fname} com comentário]: ${payload.content_text}`
    : `[O cliente enviou um documento${fname}. Pergunte como pode ajudá-lo.]`;
}

const now     = new Date();
const dateStr = now.toLocaleDateString('pt-BR', { weekday:'long', year:'numeric', month:'long', day:'numeric', timeZone:'America/Sao_Paulo' });
const timeStr = now.toLocaleTimeString('pt-BR', { hour:'2-digit', minute:'2-digit', timeZone:'America/Sao_Paulo' });

const base = agentCfg.system_prompt || 'Você é Sofia, assistente virtual de uma clínica especializada.';

const systemPrompt = `${base}
${companyContext ? `\n=== DADOS DA EMPRESA ===\n${companyContext}` : ''}
${businessProfile ? `\n=== PERFIL DA EMPRESA ===\n${businessProfile}` : ''}

${restrictToConfigured ? `=== REGRA CRÍTICA SOBRE SERVIÇOS ===
A lista "Serviços Disponíveis" contém os nomes EXATOS dos serviços cadastrados.
1. Você pode reformular, explicar e detalhar qualquer serviço da lista com suas próprias palavras.
2. NÃO mencione, invente ou sugira serviços que não constem na lista.
3. Se o cliente perguntar sobre algo fora da lista, diga que irá verificar com a equipe.` : `=== SOBRE SERVIÇOS ===
A lista "Serviços Disponíveis" contém os serviços cadastrados desta clínica. Prefira esses serviços nas respostas.
Você pode complementar com conhecimento geral sobre procedimentos e áreas de saúde quando for útil ao cliente,
mas deixe claro que o cliente deve confirmar disponibilidade diretamente com a clínica.`}

=== CONTEXTO DA CONVERSA ===
Data/hora atual: ${dateStr} às ${timeStr} (horário de Brasília, UTC-3)
ID da conversa: ${payload.conversation_id}
Cliente: ${payload.customer_name} | Telefone: ${payload.customer_phone}

=== HISTÓRICO RECENTE ===
${history || '(início da conversa)'}

=== REGRAS OBRIGATÓRIAS ===
- Responda SEMPRE em português brasileiro natural e humanizado. NUNCA mencione IA, robô ou sistemas.
- Para verificar disponibilidade de horários, use a ferramenta verificar_horarios.
- Apresente até 3 opções de horário de forma amigável. Aguarde o cliente escolher UMA opção antes de agendar.
- Use confirmar_agendamento SOMENTE após o cliente confirmar explicitamente o horário desejado.
- Ao chamar ferramentas, sempre inclua p_conversation_id = ${payload.conversation_id}
- Datas para agendamento em formato ISO com timezone -03:00. Exemplo: 2026-04-14T09:00:00-03:00
- Após confirmar agendamento, informe: serviço, profissional, data, horário e que um lembrete será enviado.
- Use consultar_agendamentos quando o cliente perguntar sobre seus agendamentos futuros (use p_include_past=true para ver o último agendamento realizado).
- Para reagendar: primeiro use consultar_agendamentos para obter o id do agendamento, depois use reagendar com p_appointment_id (id do agendamento) e p_new_start_at (novo horário ISO -03:00). Confirme o novo horário com o cliente antes de reagendar.
- Se você apresentou opções de horário e o cliente respondeu sobre outro assunto sem confirmar nem pedir outros horários, retome o tema com naturalidade e pergunte se algum dos horários sugeridos funciona ou se prefere que você verifique novas opções.`;

return [{ json: { ...payload, system_prompt: systemPrompt, user_message: userMessage }}];

const transcription = $input.first().json?.text || '';
const base = $('Enriquecer Payload').first().json;
return [{ json: { ...base, transcription_text: transcription } }];

const base = $('Normalizar Payload').first().json;
const msg  = $input.first().json || {};

// Detecta content_type pela extensão da URL se o banco retornou 'text'
let contentType = msg.content_type || base.content_type || 'text';
const url = msg.media_url || base.media_url || '';
if (url && contentType === 'text') {
  const ext = url.split('?')[0].toLowerCase().split('.').pop();
  if (['ogg','opus','mp3','m4a','wav','aac','oga'].includes(ext)) contentType = 'audio';
  else if (['mp4','avi','mov','mkv','webm'].includes(ext))         contentType = 'video';
  else if (['jpg','jpeg','png','gif','webp','heic'].includes(ext)) contentType = 'image';
  else if (['pdf','doc','docx','xls','xlsx','ppt'].includes(ext))  contentType = 'document';
}

return [{ json: {
  ...base,
  content_type:       contentType,
  media_url:          msg.media_url           || base.media_url          || null,
  transcription_text: msg.transcription_text  || base.transcription_text || null,
  media_duration_sec: msg.media_duration_sec  || base.media_duration_sec || null,
  content_text:       msg.content_text        || base.content_text       || '',
  file_name:          null,
  customer_name:      msg.customer_name       || base.customer_name      || 'Cliente',
  customer_phone:     msg.customer_phone      || base.customer_phone     || '',
}}];

// Buscar Histórico retorna N mensagens — reduz para 1 item
// para que os nós seguintes rodem uma única vez por execução.
// Preparar Contexto lê todas as mensagens via $('Buscar Histórico').all()
return [{ json: { trigger: true } }];

