// n8n 2.x stores binary data on disk — must use getBinaryDataBuffer()
const item = $input.first();
const binaryKey = Object.keys(item.binary || {})[0];
if (!binaryKey) throw new Error('ElevenLabs não retornou áudio binário');

const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
const audioBase64 = buffer.toString('base64');
return [{ json: { audio_base64: audioBase64 } }];

// n8n 2.x stores binary on disk — use getBinaryDataBuffer()
const item = $input.first();
const binaryKey = Object.keys(item.binary || {})[0];
if (!binaryKey) throw new Error('Nenhuma imagem binária recebida');

const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
const base64 = buffer.toString('base64');
const mimeType = item.binary[binaryKey].mimeType || 'image/jpeg';
return [{ json: { image_base64: base64, image_mime: mimeType } }];

