const description = $input.first().json.choices?.[0]?.message?.content || '';
const base = $('Enriquecer Payload').first().json;
return [{ json: { ...base, image_description: description } }];

// Converte markdown para formatação WhatsApp
// GPT tende a gerar **bold** e __italic__ — aqui normalizamos
let text = $('AI Agent').first().json.output || '';

// **negrito** ou __negrito__ → *negrito* (WhatsApp)
text = text.replace(/\*\*(.+?)\*\*/gs, '*$1*');
text = text.replace(/__(.+?)__/gs, '_$1_');

// ### Título → *Título* (sem # que não renderiza no WA)
text = text.replace(/^#{1,6}\s+(.+)$/gm, '*$1*');

// Remove > blockquote markers
text = text.replace(/^>\s*/gm, '');

// Remove --- e === separators
text = text.replace(/^[-=]{3,}$/gm, '');

// Espaços em branco extras no início/fim
text = text.trim();

return [{ json: { output: text } }];
